// ==============================================================
// WF2 - Moldar resposta para o frontend
// ==============================================================

const items = $input.all();
const uuid = $('Webhook').first().json.query?.uuid;

// Nenhum registro encontrado
if (!items.length || !items[0].json || !items[0].json.id) {
  return [{
    json: {
      _statusCode: 404,
      erro: 'nao_encontrado',
      mensagem: 'Link inválido ou expirado.'
    }
  }];
}

const row = items[0].json;

// Checar expiração
const agora = new Date();
const expiraEm = row.expira_em ? new Date(row.expira_em) : null;
let status = row.status;

if (status === 'aguardando' && expiraEm && agora > expiraEm) {
  status = 'expirado';
}

// Montar lista de dias (inclusive)
const dias = [];
if (row.data_inicio && row.data_fim) {
  const atual = new Date(row.data_inicio + 'T00:00:00Z');
  const fim = new Date(row.data_fim + 'T00:00:00Z');
  while (atual <= fim) {
    dias.push(atual.toISOString().slice(0, 10));
    atual.setUTCDate(atual.getUTCDate() + 1);
  }
}

return [{
  json: {
    _statusCode: 200,
    uuid: row.id,
    status,
    nome: row.nome,
    contrato: row.contrato,
    data_inicio: row.data_inicio,
    data_fim: row.data_fim,
    dias,
    expira_em: row.expira_em,
    concluido_em: row.concluido_em
  }
}];
